import xml.etree.ElementTree as ET

def parse_config(file_path):
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()

        settings = {}
        for elem in root:
            settings[elem.tag] = elem.text if elem.text else []

        return settings
    except Exception as e:
        print(f"Error occurred while parsing the config file: {str(e)}")
        return None